test "expect State.add apply rising tone for valid cases" {
    // Arrange. Each case seeds buffer_effective with spans (all .level tone),
    // dispatches a rising-tone trigger ('S' / 's'), and asserts which vowel
    // received the tone. Other spans must keep their seeded base, diacritic,
    // and .level tone. The pseudo-word scan and tone-position rules from the
    // spec drive the expected index.
    const SeedSpan = struct { base: u8, diacritic: Diacritic = .empty };
    const Case = struct {
        seeds: []const SeedSpan,
        trigger: u8,
        expected_index: u8,
    };
    const cases = [_]Case{
        // `a` -> `á`. <vowels>, single vowel, lowercase trigger.
        .{ .seeds = &.{.{ .base = 'a' }}, .trigger = 's', .expected_index = 0 },
        // `A` -> `Á`. <vowels>, single vowel, uppercase trigger.
        .{ .seeds = &.{.{ .base = 'A' }}, .trigger = 'S', .expected_index = 0 },
        // `oa` -> `óa`. <vowels>, exact OA -> tone on first vowel `o`.
        .{ .seeds = &.{ .{ .base = 'o' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 0 },
        // `uy` -> `úy`. <vowels>, exact UY -> tone on first vowel `u`.
        .{ .seeds = &.{ .{ .base = 'u' }, .{ .base = 'y' } }, .trigger = 's', .expected_index = 0 },

        // `ba` -> `bá`. <consonant><vowels>, single vowel.
        .{ .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 1 },
        // `hoa` -> `hóa`. <consonant><vowels>, exact OA -> tone on first vowel `o`.
        .{ .seeds = &.{ .{ .base = 'h' }, .{ .base = 'o' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 1 },
        // `huy` -> `húy`. <consonant><vowels>, exact UY -> tone on first vowel `u`.
        .{ .seeds = &.{ .{ .base = 'h' }, .{ .base = 'u' }, .{ .base = 'y' } }, .trigger = 's', .expected_index = 1 },
        // `gia` -> `giá`. <consonant><vowels>, GI special -> `i` joins consonant, tone on `a`.
        .{ .seeds = &.{ .{ .base = 'g' }, .{ .base = 'i' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 2 },
        // `qua` -> `quá`. <consonant><vowels>, QU special -> `u` joins consonant, tone on `a`.
        .{ .seeds = &.{ .{ .base = 'q' }, .{ .base = 'u' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 2 },

        // `an` -> `án`. <vowels><consonants>, single vowel.
        .{ .seeds = &.{ .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 0 },
        // `oan` -> `oán`. <vowels><consonants>, extended OA -> tone on second vowel `a`.
        .{ .seeds = &.{ .{ .base = 'o' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 1 },
        // `uyn` -> `uýn`. <vowels><consonants>, extended UY -> tone on second vowel `y`.
        .{ .seeds = &.{ .{ .base = 'u' }, .{ .base = 'y' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 1 },

        // `ban` -> `bán`. <consonant><vowels><consonants>, single vowel.
        .{ .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 1 },
        // `quan` -> `quán`. <consonant><vowels><consonants>, QU special -> tone on `a`.
        .{ .seeds = &.{ .{ .base = 'q' }, .{ .base = 'u' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 'S', .expected_index = 2 },
        // `gian` -> `gián`. <consonant><vowels><consonants>, GI special -> tone on `a`.
        .{ .seeds = &.{ .{ .base = 'g' }, .{ .base = 'i' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 2 },
        // `hoan` -> `hoán`. <consonant><vowels><consonants>, extended OA -> tone on second vowel `a`.
        .{ .seeds = &.{ .{ .base = 'h' }, .{ .base = 'o' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 2 },
        // `huynh` -> `huýnh`. <consonant><vowels><consonants>, extended UY -> tone on second vowel `y`.
        .{ .seeds = &.{ .{ .base = 'h' }, .{ .base = 'u' }, .{ .base = 'y' }, .{ .base = 'n' }, .{ .base = 'h' } }, .trigger = 'S', .expected_index = 2 },

        // `uơp` -> `uớp`. Ơ priority -> tone on `ơ` over plain `u`.
        .{ .seeds = &.{ .{ .base = 'u' }, .{ .base = 'o', .diacritic = .horn }, .{ .base = 'p' } }, .trigger = 's', .expected_index = 1 },
        // `tiên` -> `tiến`. Ê priority -> tone on `ê` over plain `i`.
        .{ .seeds = &.{ .{ .base = 't' }, .{ .base = 'i' }, .{ .base = 'e', .diacritic = .circumflex }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 2 },
        // `dâu` -> `dấu`. Â priority -> tone on `â` over plain `u`.
        .{ .seeds = &.{ .{ .base = 'd' }, .{ .base = 'a', .diacritic = .circumflex }, .{ .base = 'u' } }, .trigger = 's', .expected_index = 1 },
        // `tuôn` -> `tuốn`. Ô priority -> tone on `ô` over plain `u`.
        .{ .seeds = &.{ .{ .base = 't' }, .{ .base = 'u' }, .{ .base = 'o', .diacritic = .circumflex }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 2 },
        // `loăt` -> `loắt`. Ă priority -> tone on `ă` over plain `o`.
        .{ .seeds = &.{ .{ .base = 'l' }, .{ .base = 'o' }, .{ .base = 'a', .diacritic = .breve }, .{ .base = 't' } }, .trigger = 's', .expected_index = 2 },
        // `tưu` -> `tứu`. Ư priority -> tone on `ư` over plain `u`.
        .{ .seeds = &.{ .{ .base = 't' }, .{ .base = 'u', .diacritic = .horn }, .{ .base = 'u' } }, .trigger = 's', .expected_index = 1 },
        // `ăê` -> `ăế`. Ê before Ă in Ê/Â/Ô/Ă/Ư ordering -> tone on `ê`.
        .{ .seeds = &.{ .{ .base = 'a', .diacritic = .breve }, .{ .base = 'e', .diacritic = .circumflex } }, .trigger = 's', .expected_index = 1 },

        // `thethuy` -> `thethúy`. Suffix pseudo-word `huy`, exact UY -> tone on `u`.
        .{ .seeds = &.{ .{ .base = 't' }, .{ .base = 'h' }, .{ .base = 'e' }, .{ .base = 't' }, .{ .base = 'h' }, .{ .base = 'u' }, .{ .base = 'y' } }, .trigger = 's', .expected_index = 5 },
        // `vanhoa` -> `vanhóa`. Suffix pseudo-word `hoa`, exact OA -> tone on `o`.
        .{ .seeds = &.{ .{ .base = 'v' }, .{ .base = 'a' }, .{ .base = 'n' }, .{ .base = 'h' }, .{ .base = 'o' }, .{ .base = 'a' } }, .trigger = 's', .expected_index = 4 },
        // `baoquan` -> `baoquán`. Suffix pseudo-word `quan`, QU special -> tone on `a`.
        .{ .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' }, .{ .base = 'o' }, .{ .base = 'q' }, .{ .base = 'u' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 5 },
        // `bogian` -> `bogián`. Suffix pseudo-word `gian`, GI special -> tone on `a`.
        .{ .seeds = &.{ .{ .base = 'b' }, .{ .base = 'o' }, .{ .base = 'g' }, .{ .base = 'i' }, .{ .base = 'a' }, .{ .base = 'n' } }, .trigger = 's', .expected_index = 4 },
    };

    for (cases) |c| {
        var state: State = undefined;
        state.init();
        state.mode = .telex;
        for (c.seeds, 0..) |s, i| {
            state.buffer_effective[i] = Span.init_diacritic_tone(s.base, s.diacritic, .level);
        }
        state.buffer_length = @intCast(c.seeds.len);

        // Act
        state.add(c.trigger);

        // Assert: rising tone is applied in place; bookkeeping fields stay clean.
        try expectEqual(@as(u8, @intCast(c.seeds.len)), state.buffer_length);
        try expectEqual(@as(?u8, c.expected_index), state.buffer_modification_index);
        try expectEqual(null, state.literal_index);
        try expectEqual(.telex, state.mode);

        // The targeted vowel gets .rising; every other span keeps base, diacritic
        // and stays at .level.
        for (c.seeds, 0..) |s, i| {
            const sp = state.buffer_effective[i];
            try expectEqual(s.base, sp.base);
            try expectEqual(s.diacritic, sp.diacritic);
            const expected_tone: Tone = if (i == @as(usize, c.expected_index)) .rising else .level;
            try expectEqual(expected_tone, sp.tone);
        }
    }
}

test "expect State.backspace will reduce buffer_length by 1 and won't touch literal_index" {
    // Arrange

// and the engine is working on position on or after literal index, the engine will skip
// Vietnamese input processing (we only count valid numbers, null mean no literal index).
literal_index: ?u8 = null,
// Determine if we will process input in the specified mode (Telex) or append the character as is.
mode: InputMode = .literal,

// Initialize the State on allocated memory.
fn init(self: *State) void {
    self.* = .{
        .buffer_effective = undefined,
    };
}

fn add(self: *State, c: u8) void {
    // Only allow a-zA-Z.
    assert(std.ascii.isAlphabetic(c));

    // Input mode must be either .literal or .telex.
    assert(self.mode == .literal or self.mode == .telex);

    // Should never set literal_index in .literal mode.
    if (self.mode == .literal) {
        assert(self.literal_index == null);
    }

    if (self.literal_index) |literal_index| {
        // When literal_index is set, mode must be .telex.
        assert(self.mode == .telex);
        // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
        // because we won't process Vietnamese input outside the buffer_effective.
        assert(literal_index <= self.buffer_effective.len);
        // The literal_index value must be less than buffer length.
        assert(literal_index < self.buffer_length);
    }

    // buffer_length conditions
    // 1. must be within buffer_effective length in Vietnamese input.
    // 2. could be more than buffer_effective in literal input.
    assert(self.buffer_length <= self.buffer_effective.len or self.mode == .literal or self.literal_index != null);

    // Reset buffer_modification_index to start the new action.
    self.buffer_modification_index = null;

    switch (c) {
        'A', 'a' => {
            if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
                // 1. Enable literal input when literal_index is set or on literal mode. The
                // literal_index is also set when the word starts with non-Vietnamese onsets.
                // 2. Append literal because no previous span existed. Continue Vietnamese
                // processing on next input.
                self.append_literal(c);
                // Set modification index to null because we didn't modify any existing span.
                self.buffer_modification_index = null;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
                // 3. Previous span is 'A' or 'a', apply circumflex.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
                // Set modification index for calculating synthetic backspace.
                self.buffer_modification_index = self.buffer_length - 1;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .breve)) {
                // 4. Previous span is 'Ă' or 'ă', override to circumflex.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
                // Set modification index for calculating synthetic backspace.
                self.buffer_modification_index = self.buffer_length - 1;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .circumflex)) {
                // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
                // Set modification index for calculating synthetic backspace.
                self.buffer_modification_index = self.buffer_length - 1;
                // Start literal input from this position.
                self.literal_index = self.buffer_length;
                // Append literal 'A' or 'a'.
                self.append_literal(c);
            } else if (!self.buffer_effective_last().equals_base(c)) {
                // 6. Append literal when previous span is not 'A', 'a' and its variants.
                self.append_literal(c);
                // No modification.
                self.buffer_modification_index = null;
            } else {
                unreachable;
            }
        },
        'C', 'c' => { // fill missing diacritic, e.g. cước.
            if (self.literal_index != null or self.mode == .literal or self.buffer_length < 2) {
                // 1. Enable literal input when literal_index is set or on literal mode. The
                // literal_index is also set when the word starts with non-Vietnamese onsets.
                // 2. Append literal because no previous span existed. Continue Vietnamese
                // processing on next input.
                // 3. Buffer is less than 2 characters to start with.
                self.append_literal(c);
                // Set modification index to null because we didn't modify any existing span.
                self.buffer_modification_index = null;
            } else if (self.buffer_effective[self.buffer_length - 2].equals_ignore_case_and_tone('U', .empty) and self.buffer_effective[self.buffer_length - 1].equals_ignore_case_and_tone('O', .horn)) {
                // 4. Pattern: 'UƠ', fill missing horn on 'U'.
                const span_previous2 = self.buffer_effective[self.buffer_length - 2];
                self.buffer_effective[self.buffer_length - 2] = Span.init_diacritic_tone(span_previous2.base, .horn, span_previous2.tone);
                self.buffer_modification_index = self.buffer_length - 2;
                // Append the new character literally.
                self.append_literal(c);
            } else if (self.buffer_effective[self.buffer_length - 2].equals_ignore_case_and_tone('U', .horn) and self.buffer_effective[self.buffer_length - 1].equals_ignore_case_and_tone('O', .empty)) {
                // 5. Pattern: 'ƯO', fill missing horn on 'O'.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .horn, span_previous.tone);
                self.buffer_modification_index = self.buffer_length - 1;
                // Append the new character literally.
                self.append_literal(c);
            } else {
                // 6. No pattern matched, append literally.
                self.append_literal(c);
                self.buffer_modification_index = null;
            }
        },
        'D', 'd' => { // stroke.
            if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
                // 1. Enable literal input when literal_index is set or on literal mode. The
                // literal_index is also set when the word starts with non-Vietnamese onsets.
                // 2. Append literal because no previous span existed. Continue Vietnamese
                // processing on next input.
                self.append_literal(c);
                // Set modification index to null because we didn't modify any existing span.
                self.buffer_modification_index = null;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
                // 3. Previous span is 'D' or 'd', apply stroke.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .stroke, span_previous.tone);
                // Set modification index for calculating synthetic backspace.
                self.buffer_modification_index = self.buffer_length - 1;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .stroke)) {
                // 4. Previous span is 'Đ' or 'đ', cancel stroke for previous span and append new literal span.
                const span_previous = self.buffer_effective[self.buffer_length - 1];
                self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
                // Set modification index for calculating synthetic backspace.
                self.buffer_modification_index = self.buffer_length - 1;
                // Start literal input from this position.
                self.literal_index = self.buffer_length;
                // Append literal 'D' or 'd'.
                self.append_literal(c);
            } else if (!self.buffer_effective_last().equals_base(c)) {
                // 5. Append literal when previous span is not 'D', 'd' and its variants.
                self.append_literal(c);
                // No modification.
                self.buffer_modification_index = null;
            } else {
                unreachable;
            }
        },
        'E', 'e' => {
            if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
                // 1. Enable literal input when literal_index is set or on literal mode. The
                // literal_index is also set when the word starts with non-Vietnamese onsets.
                // 2. Append literal because no previous span existed. Continue Vietnamese
                // processing on next input.
                self.append_literal(c);
                // Set modification index to null because we didn't modify any existing span.
                self.buffer_modification_index = null;
            } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
                // 3. Previous span is 'E' or 'e', apply circumflex.
